def train_model():
    """Train the spam detection model with evasion-resistant preprocessing."""
    global model_pipeline
    
    texts, labels = get_training_data()
    
    # Preprocess all training texts with the same normalization
    preprocessed_texts = [preprocess_text(t) for t in texts]
    
    # Use TF-IDF with character n-grams in addition to word n-grams
    # Character n-grams help detect obfuscated spam words
    word_vectorizer = TfidfVectorizer(
        analyzer='word',
        ngram_range=(1, 2),
        max_features=5000,
        min_df=1,
        max_df=0.95,
        sublinear_tf=True,
    )
    
    char_vectorizer = TfidfVectorizer(
        analyzer='char_wb',
        ngram_range=(3, 5),
        max_features=5000,
        min_df=1,
        max_df=0.95,
        sublinear_tf=True,
    )
    
    # Combine word and character features
    from sklearn.pipeline import FeatureUnion
    
    combined_features = FeatureUnion([
        ('word_tfidf', word_vectorizer),
        ('char_tfidf', char_vectorizer),
    ])
    
    # Use LogisticRegression with regularization to improve robustness
    model_pipeline = Pipeline([
        ('features', combined_features),
        ('classifier', LogisticRegression(
            C=1.0,
            penalty='l2',
            solver='lbfgs',
            max_iter=1000,
            class_weight='balanced',  # Handle class imbalance
        ))
    ])
    
    model_pipeline.fit(preprocessed_texts, labels)
    
    # Evaluate on training data (in production, use proper train/test split)
    train_accuracy = model_pipeline.score(preprocessed_texts, labels)
    print(f"Model trained. Training accuracy: {train_accuracy:.4f}")
    
    return model_pipeline


def compute_additional_spam_signals(text, preprocessed_text):
    """Compute rule-based features that are harder to evade."""
    signals = {}
    
    # Check for excessive capitalization in original text
    if len(text) > 0:
        upper_ratio = sum(1 for c in text if c.isupper()) / max(len(text), 1)
        signals['excessive_caps'] = upper_ratio > 0.5
    else:
        signals['excessive_caps'] = False
    
    # Check for suspicious URL patterns
    url_count = len(re.findall(r'https?://|www\.', text.lower()))
    signals['many_urls'] = url_count > 3
    
    # Check for urgency words
    urgency_words = {'urgent', 'immediately', 'act now', 'limited time', 
                     'hurry', 'expires', 'deadline', 'last chance'}
    signals['has_urgency'] = any(w in preprocessed_text for w in urgency_words)
    
    # Check for excessive punctuation (!!!, ???, etc.)
    exclamation_count = text.count('!')
    signals['excessive_punctuation'] = exclamation_count > 3
    
    # Check for obfuscation attempts (many special characters between letters)
    obfuscation_pattern = re.findall(r'[a-zA-Z][^a-zA-Z\s]{1,2}[a-zA-Z]', text)
    signals['possible_obfuscation'] = len(obfuscation_pattern) > 5
    
    return signals


def get_spam_probability(text):
    """Get spam probability with multi-layered detection."""
    if model_pipeline is None:
        raise RuntimeError("Model not trained")
    
    # Preprocess with anti-evasion normalization
    preprocessed = preprocess_text(text)
    
    if not preprocessed.strip():
        # Empty after preprocessing is suspicious
        return 0.5, {"warning": "Text was empty after preprocessing"}
    
    # Get ML model probability
    ml_probability = model_pipeline.predict_proba([preprocessed])[0][1]
    
    # Get rule-based signals
    signals = compute_additional_spam_signals(text, preprocessed)
    
    # Combine ML score with rule-based signals
    # Boost spam probability if multiple suspicious signals are present
    signal_boost = 0.0
    active_signals = sum(1 for v in signals.values() if v)
    if active_signals >= 3:
        signal_boost = 0.15
    elif active_signals >= 2:
        signal_boost = 0.08
    elif active_signals >= 1:
        signal_boost = 0.03
    
    # Combined probability (weighted)
    final_probability = min(1.0, ml_probability * 0.85 + signal_boost + 0.15 * ml_probability)
    
    return final_probability, {
        "ml_score": float(ml_probability),
        "signal_boost": float(signal_boost),
        "active_signals": active_signals,
        "signals": {k: bool(v) for k, v in signals.items()},
    }


@app.route('/predict', methods=['POST'])
def predict():
    """API endpoint to classify email text as spam or ham."""
    try:
        data = request.get_json()
        
        if not data or 'text' not in data:
            return jsonify({
                'error': 'Missing required field: text'
            }), 400
        
        email_text = data['text']
        
        if not isinstance(email_text, str):
            return jsonify({
                'error': 'Field "text" must be a string'
            }), 400
        
        if len(email_text) == 0:
            return jsonify({
                'error': 'Field "text" must not be empty'
            }), 400
        
        # Limit input size
        if len(email_text) > 100000:
            return jsonify({
                'error': 'Input text exceeds maximum allowed length (100000 characters)'
            }), 400
        
        spam_probability, details = get_spam_probability(email_text)
        
        # Use a threshold with a buffer zone
        if spam_probability >= 0.7:
            classification = 'spam'
        elif spam_probability >= 0.4:
            classification = 'suspicious'
        else:
            classification = 'ham'
        
        return jsonify({
            'spam_probability': round(float(spam_probability), 4),
            'classification': classification,
            'is_spam': spam_probability >= 0.5,
            'details': details,
        })
    
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        # Don't leak internal error details
        app.logger.error(f"Prediction error: {str(e)}")
        return jsonify({'error': 'Internal server error during prediction'}), 500


